const ACTIVITY_PRESETS = [
  ["座って過ごす（1.2 MET）", 1.2],
  ["立ち仕事・ゆっくり歩き（2.0 MET）", 2.0],
  ["早歩き（3.3 MET）", 3.3],
  ["観光で長く歩く（4.0 MET）", 4.0],
  ["軽い運動（5.0 MET）", 5.0],
  ["部活・ランニング（8.0 MET）", 8.0],
  ["重労働（10.0 MET）", 10.0],
];

const LEVEL_STYLE = {
  "低":   {bg:"#E8F5E9", fg:"#1B5E20"},
  "注意": {bg:"#FFF8E1", fg:"#E65100"},
  "警戒": {bg:"#FFEBEE", fg:"#B71C1C"},
  "危険": {bg:"#4A148C", fg:"#FFFFFF"},
};

function riskScoreFromWbgtFine(wbgt, age, met, waterMlLast2h) {
  let base;
  if (wbgt < 25) base = 10;
  else if (wbgt < 28) base = 25;
  else if (wbgt < 31) base = 45;
  else base = 65;

  const ageAdd = (age >= 65) ? 10 : (age < 15 ? 5 : 0);

  const metClamped = Math.max(1.0, Math.min(10.0, met));
  const activityAdd = (metClamped - 1.0) / 9.0 * 20.0;

  const ml = Math.max(0.0, waterMlLast2h);
  const hydrationAdd = 18.0 * (1.0 - Math.min(1.0, ml / 600.0));

  const score = Math.round(Math.min(100.0, base + ageAdd + activityAdd + hydrationAdd));

  let level;
  if (score <= 24) level = "低";
  else if (score <= 49) level = "注意";
  else if (score <= 74) level = "警戒";
  else level = "危険";

  return [score, level];
}

function recommendAction(level) {
  return {
    "低": "通常注意：こまめに水分補給。",
    "注意": "日陰・屋内を優先、30〜60分ごと休憩。",
    "警戒": "外出/運動は時間をずらす（朝夕へ）。",
    "危険": "今は避ける：屋内へ移動し活動は中止。"
  }[level];
}

let waterMl = 0;
let selectedIdx = 0;
let heatLayer = null;


function nearestGridIndex(lat, lon) {
  let bestI = 0, bestD = Infinity;
  const pts = DATA.grid.latlon;
  for (let i=0;i<pts.length;i++) {
    const dlat = pts[i][0]-lat;
    const dlon = pts[i][1]-lon;
    const d = dlat*dlat + dlon*dlon;
    if (d < bestD) { bestD = d; bestI = i; }
  }
  return bestI;
}

function setCard(timeKey) {
  const age = parseInt(document.getElementById("age").value, 10);
  const met = parseFloat(document.getElementById("metSelect").value);
  const wbgt = DATA.wbgt[timeKey][selectedIdx];

  const [score, level] = riskScoreFromWbgtFine(wbgt, age, met, waterMl);
  const style = LEVEL_STYLE[level];

  const card = document.getElementById("card");
  card.style.background = style.bg;
  card.style.color = style.fg;

  const latlon = DATA.grid.latlon[selectedIdx];
  document.getElementById("cardTop").textContent =
    `${timeKey} / 地点(${latlon[0].toFixed(4)}, ${latlon[1].toFixed(4)}) / WBGT≈${wbgt.toFixed(1)}`;

  document.getElementById("cardScore").textContent =
    `リスクスコア：${score}/100（${level}）`;

  document.getElementById("cardDetail").textContent =
    `年齢：${age} / 行動MET：${met} / 水分：${waterMl}ml`;

  document.getElementById("cardAction").textContent =
    `✅ 推奨アクション：${recommendAction(level)}`;

  document.getElementById("barFill").style.width = `${score}%`;
  document.getElementById("barFill").style.background = style.fg;

  document.getElementById("interpMeta").textContent =
    `補間：IDW（k=${DATA.meta.k}, power=${DATA.meta.power}） / WBGTモデル：日陰近似`;
}

function updateHeat(timeKey) {
  const points = DATA.grid.latlon;
  const wbgtArr = DATA.wbgt[timeKey];
  const heatData = points.map((p, i) => [p[0], p[1], wbgtArr[i]]);

  if (heatLayer) heatLayer.setLatLngs(heatData);
  else heatLayer = L.heatLayer(heatData, {radius: 18, blur: 22, maxZoom: 10}).addTo(map);
}

function refresh() {
  const timeKey = document.getElementById("timeSelect").value;
  updateHeat(timeKey);
  setCard(timeKey);
}

// risklib.js の末尾に追加
function wbgtAtLatLon(lat, lon, timeKey) {
  const idx = nearestGridIndex(lat, lon);
  const arr = DATA.wbgt[timeKey];
  if (!arr) throw new Error("timeKey が不正: " + timeKey);
  return { idx, gridLatLon: DATA.grid.latlon[idx], wbgt: arr[idx] };
}

function riskFromLatLon(lat, lon, timeKey, { age=30, met=4.0, waterMlLast2h=0 } = {}) {
  const { idx, gridLatLon, wbgt } = wbgtAtLatLon(lat, lon, timeKey);
  const [score, level] = riskScoreFromWbgtFine(wbgt, age, met, waterMlLast2h);
  return { idx, gridLatLon, wbgt, score, level, action: recommendAction(level) };
}

window.RiskLib = { DATA, nearestGridIndex, wbgtAtLatLon, riskFromLatLon, riskScoreFromWbgtFine, recommendAction };